var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`어머, 애가 피아노를 참 빨리 배운다니까요? 이번 콩쿨에선 분명 금상을 탈 거에요.`,JPN:`まあ、この子ったら上達がとても早いんですのよ。
今度のピアノコンクールは金賞間違いなしですわ。`,ENG:`Oh my, she's learning the piano really quickly! I'm sure she'll win first prize in the upcoming recital.`,TWN:`哎呀，這孩子很有彈鋼琴的天分啊？這次比賽肯定能拿金牌。`},stage:{bg:`BACKSTREET`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`그럼~ 우리 학교에서 루미만큼 노래 잘 하는 애는 없을걸? 당연히 1등하겠지.`,JPN:`そうそう！　うちの学校でルミよりも歌の上手い子はいないわよ。そりゃもちろん1位でしょうね。`,ENG:`Of course, nobody sings better than Lumi at our school! I'm sure she'll win first place.`,TWN:`當然啦～我們學校裡，應該沒有唱歌唱得比魯米好的人吧？她當然是第一名啦。`},stage:{bg:`BACKSTREET`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`춤 잘 춘다며? 오디션 한 번 나가보지 않을래? 너라면 분명 가능할 거야.`,JPN:`踊りが上手なのよね？　一度オーディションに出てみたら？　あなたにならきっとできるわ。`,ENG:`Hey, I heard you're a great dancer. Why don't you try out for an audition? I'm sure you could pull it off.`,TWN:`聽說妳跳舞跳得很棒？要不要來參加試鏡看看？是妳的話，一定可以辦到的。`},stage:{bg:`BACKSTREET`,slots:{L:null,C:null,R:null}}},{id:`L7_1`,type:`subtitle`,speaker:null,text:{KOREA:`루미, 하트베리 데뷔 D-day`,JPN:`ルミ、ハートベリーとしてのデビューD-day。`,ENG:`Lumi's Debut with HRT Berry`,TWN:`魯米，愛心莓果出道日D-day`,THA:`รูมีเดบิวต์กับ HRT เบอร์รี่`,VTN:`Màn Ra Mắt của Lumi cùng với Quả Mọng Tình Yêu`,SCN:`鲁米，爱心莓果出道日D-day`,DEU:`Lumis Debüt bei HRT Berry`,FRA:`Les débuts de Lumi avec HRT Berry`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L10_1`,type:`dialog`,speaker:`RUMI_HB_NULL_NULL`,text:{KOREA:`......바보들.`,JPN:`……バカばっか。`,ENG:`Stupid...`,TWN:`……一群笨蛋。`},stage:{bg:`CITY_CENTER1`,slots:{L:null,C:{char_id:`RUMI_HB_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`RUMI_HB_NULL_NULL`,text:{KOREA:`심사위원들은 하나 같이 다 바보들뿐이야.`,JPN:`審査員たちって、揃いも揃ってバカばっかよ。`,ENG:`All those judges are stupid.`,TWN:`評審都是一群笨蛋。`},stage:{bg:`CITY_CENTER1`,slots:{L:null,C:{char_id:`RUMI_HB_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`RUMI_HB_NULL_NULL`,text:{KOREA:`내가 더 잘했는데...... 왜 항상 1등은 다른 애냐고.`,JPN:`アタシの方が上手くできたのに……どうしていつも他の子が1位なのよ。`,ENG:`I was a lot better... How come the first place always goes to someone else?`,TWN:`明明我做得更好啊……為什麼第一名總是別人。`},stage:{bg:`CITY_CENTER1`,slots:{L:null,C:{char_id:`RUMI_HB_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`RUMI_HB_NULL_NULL`,text:{KOREA:`정말......`,JPN:`まったく……`,ENG:`Seriously...`,TWN:`真是的……`},stage:{bg:`CITY_CENTER1`,slots:{L:null,C:{char_id:`RUMI_HB_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:null,text:{KOREA:`엇, 저게 뭐지? 유원지 쪽에서 엄청난 게......`,JPN:`ちょっ、ありゃ何なんだ？　遊園地の方からとんでもないものが……`,ENG:`Huh? What's that? There's something huge coming from the park...`,TWN:`咦，那是什麼？遊樂園那邊好像有什麼……`},stage:{bg:`CITY_CENTER1`,slots:{L:null,C:{char_id:`RUMI_HB_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:null,text:{KOREA:`으아악- 코, 코끼리다!`,JPN:`うわあーっ、ゾ、ゾウだ！`,ENG:`Eeek! It's an elephant!`,TWN:`哇啊啊—是、是大象！`},stage:{bg:`CITY_CENTER1`,slots:{L:null,C:{char_id:`RUMI_HB_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`RUMI_HB_NULL_NULL`,text:{KOREA:`어, 어? 뭐야, 갑자기? 왜 저런 게 달려오는데?`,JPN:`え、え？　何なの、いきなり？　どうしてあんなのが駆け寄ってくるの？`,ENG:`Err... Huh? What's that? What is something like that running this way?`,TWN:`咦，咦？怎麼了，這麼突然？為什麼牠往這邊跑過來了？`},stage:{bg:`CITY_CENTER1`,slots:{L:null,C:{char_id:`RUMI_HB_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L21_1`,type:`dialog`,speaker:null,text:{KOREA:`이런, 마취총을 맞혔더니 더 흥분했어!`,JPN:`いかん、麻酔銃を撃ったら余計に興奮しちまった！`,ENG:`The tranquilizer darts only made it angrier!`,TWN:`明明被麻醉槍擊中了，結果牠竟然變得更亢奮了！`},stage:{bg:`CITY_CENTER1`,slots:{L:null,C:null,R:null}}},{id:`L22_1`,type:`dialog`,speaker:null,text:{KOREA:`도보로 도망간다! 거기 피해요!`,JPN:`歩道に逃げたわ！　ねぇ！　避けて！`,ENG:`It's headed for the sidewalk! Get out of the way!`,TWN:`牠逃走了！那邊的快躲開！`},stage:{bg:`CITY_CENTER1`,slots:{L:null,C:null,R:null}}},{id:`L23_1`,type:`dialog`,speaker:`RUMI_HB_NULL_NULL`,text:{KOREA:`윽, 나도 어서 도망쳐야......`,JPN:`うっ、アタシも早く逃げなきゃ……`,ENG:`Whoa, I'd better run away...`,TWN:`呃，我也得快點逃……`},stage:{bg:`CITY_CENTER1`,slots:{L:null,C:{char_id:`RUMI_HB_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L26_1`,type:`dialog`,speaker:null,text:{KOREA:`꺄악! 저기 사람이 위험해요!`,JPN:`きゃあっ！　あの人、危ないわ！`,ENG:`Eeek! There's someone in danger!`,TWN:`呀啊！那邊的人有危險！`},stage:{bg:`CITY_CENTER1`,slots:{L:null,C:null,R:{char_id:`RUMI_HB_NULL_NULL`,face:`UNIT_SURPRISE`}}}}];export{e as default};